+fn build_numpy_tuple_from_pyarrays(py: Python<'_>, arrays: &[Py<PyAny>]) -> PyResult<Py<PyAny>> {
+    Ok(PyTuple::new(py, arrays.iter().map(|array| array.bind(py)))?
